import{_ as o,o as c,c as d,ae as a}from"./chunks/framework.Czhw_PXq.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"releases/1.8.0.zh-CN.md","filePath":"releases/1.8.0.zh-CN.md"}'),l={name:"releases/1.8.0.zh-CN.md"};function i(r,e,t,n,s,h){return c(),d("div",null,[...e[0]||(e[0]=[a('<h3 id="核心亮点" tabindex="-1">核心亮点 <a class="header-anchor" href="#核心亮点" aria-label="Permalink to &quot;核心亮点&quot;">​</a></h3><p>本次版本为 Notemd 建立了第一性原理的语言支持底座：UI 语言与任务输出语言被明确拆分，并通过统一策略层解析。这样可以消除历史上分散在各任务链路中的语言分支逻辑，使处理、研究、生成、Mermaid 摘要和翻译相关流程的语言行为更一致、更可预测。</p><p>同时，本版本显著提升了可维护性和发布稳定性。项目新增了可复现的 baseline/compare 回归脚本与前后证据沉淀，并将 <code>ref/**</code> 参考仓与主工程的构建/测试边界隔离。对维护者来说，这一版能明显降低后续功能扩展时的回归风险。</p><h3 id="破坏性更新" tabindex="-1">破坏性更新 <a class="header-anchor" href="#破坏性更新" aria-label="Permalink to &quot;破坏性更新&quot;">​</a></h3><ul><li><strong>无需用户侧迁移操作</strong>：升级后会自动回退到 <code>uiLocale: auto</code>，并保持既有任务语言配置行为，无需手动改配置。</li></ul><h3 id="新特性" tabindex="-1">新特性 <a class="header-anchor" href="#新特性" aria-label="Permalink to &quot;新特性&quot;">​</a></h3><ul><li><code>feat</code>: 新增统一语言域模型（<code>uiLocale</code> + 任务语言策略），集中管理语言决策。</li><li><code>feat</code>: 新增 UI i18n 基础设施，为全部受支持的 UI locale（<code>en</code>、<code>ar</code>、<code>de</code>、<code>es</code>、<code>fa</code>、<code>fr</code>、<code>id</code>、<code>it</code>、<code>ja</code>、<code>ko</code>、<code>nl</code>、<code>pl</code>、<code>pt</code>、<code>pt-BR</code>、<code>ru</code>、<code>th</code>、<code>tr</code>、<code>uk</code>、<code>vi</code>、<code>zh-CN</code>、<code>zh-TW</code>）提供集中式语言目录，并支持回退链与变量插值。</li><li><code>feat</code>: 将设置页、侧边栏、错误弹窗和关键运行时提示迁移到共享 i18n 字符串体系。</li><li><code>feat</code>: 新增本地化时间格式化与 RTL 安全样式保护，增强多语言展示稳定性。</li><li><code>feat</code>: 新增脚本化回归流程（<code>regression:language-baseline</code>、<code>regression:language-compare</code>），支持可复现的前后对比验证。</li></ul><h3 id="bug-修复" tabindex="-1">Bug 修复 <a class="header-anchor" href="#bug-修复" aria-label="Permalink to &quot;Bug 修复&quot;">​</a></h3><ul><li><code>fix</code>: 修复了 prompt/process/search/translate 路径中语言决策分散导致的任务输出语言不一致问题。</li><li><code>fix</code>: 修复了在 <code>ref/</code> 下克隆参考项目时可能引发的构建不稳定问题（将 <code>ref/**</code> 排除出 TypeScript/Jest/ESLint 范围）。</li><li><code>fix</code>: 修复了部分运行时 UI 提示未统一走语言中台、导致语言不一致的问题。</li></ul><h3 id="重构与杂项" tabindex="-1">重构与杂项 <a class="header-anchor" href="#重构与杂项" aria-label="Permalink to &quot;重构与杂项&quot;">​</a></h3><ul><li><code>refactor</code>: 将任务语言解析收敛到共享策略层，并接入主执行路径。</li><li><code>refactor</code>: 新增 i18n 工具模块，覆盖 locale 归一化、回退合并与格式化。</li><li><code>chore</code>: 补齐语言策略、i18n 回退与本地化格式化测试。</li><li><code>chore</code>: 增加 baseline 证据与 release handoff 文档，完善可复验流程。</li><li><code>docs</code>: 更新 <code>README.md</code> 与 <code>README_zh.md</code>，补充语言架构、回归工作流和双语发布规范。</li></ul><h3 id="致谢" tabindex="-1">致谢 <a class="header-anchor" href="#致谢" aria-label="Permalink to &quot;致谢&quot;">​</a></h3><p>感谢 <code>@Jacobinwwey</code> 推进语言支持架构改造、回归体系建设与文档完善。</p>',13)])])}const p=o(l,[["render",i]]);export{f as __pageData,p as default};
